package connections

import (
	"context"
	"sync"

	eventspb "github.com/klever-io/klever-ex-events-protocol"
)

// SyncOrderConnection stream order connection
type SyncOrderConnection struct {
	lock      sync.RWMutex
	active    bool
	error     chan error
	orderID   string
	operation string
	stream    eventspb.EventsService_SubscribeSyncOrdersServer
}

var _ ConnectionHandler = (*SyncOrderConnection)(nil)

// GetError return connection error channel
func (o *SyncOrderConnection) GetError() chan error {
	return o.error
}

// GetOrderID get the id of an order
func (o *SyncOrderConnection) GetOrderID() string {
	return o.orderID
}

// GetOperation get operation type of the caller
func (o *SyncOrderConnection) GetOperation() string {
	return o.operation
}

// GetActive get connection status (active/deactivated)
func (o *SyncOrderConnection) GetActive() bool {
	return o.active
}

// Send stream data to rpc
func (o *SyncOrderConnection) Send(m interface{}) error {
	return o.stream.Send(m.(*eventspb.StreamSyncOrdersResponse))
}

// Throw error and close connection
func (o *SyncOrderConnection) Throw(err error) {
	o.error <- err
	o.Stop()
}

// Stop connection by setting to inactive
func (o *SyncOrderConnection) Stop() {
	o.lock.Lock()
	o.active = false
	o.lock.Unlock()
}

type connsSyncOrderController struct {
	lock  sync.RWMutex
	conns []*SyncOrderConnection
}

// GetConnections get all current connections
func (o *connsSyncOrderController) GetConnections() []*SyncOrderConnection {
	o.lock.Lock()
	defer o.lock.Unlock()
	return o.conns
}

// New return new Orders connection and add to controller
func (o *connsSyncOrderController) New(ctx context.Context, stream eventspb.EventsService_SubscribeSyncOrdersServer, orderID, operation string) *SyncOrderConnection {
	newConn := &SyncOrderConnection{
		active:    true,
		error:     make(chan error),
		stream:    stream,
		orderID:   orderID,
		operation: operation,
	}
	o.lock.Lock()
	o.conns = append(o.conns, newConn)
	o.lock.Unlock()
	return newConn
}

// Clean remove inactive and unused connections
func (o *connsSyncOrderController) Clean() {
	var updtConns []*SyncOrderConnection
	for i := 0; i < len(o.conns); i++ {
		if o.conns[i] != nil && o.conns[i].active {
			updtConns = append(updtConns, o.conns[i])
		}
	}
	o.lock.Lock()
	o.conns = updtConns
	o.lock.Unlock()
}

package connections

type ConnectionHandler interface {
	GetError() chan error
	GetActive() bool
	Throw(error)
	Stop()
	Send(interface{}) error
}

// Controllers
var (
	SyncOrder       = &connsSyncOrderController{}
)

// SubscribeSyncOrders subscribe to receive orders status info from core
func (*EventsServer) SubscribeSyncOrders(req *eventspb.ConnectSyncOrders, stream eventspb.EventsService_SubscribeSyncOrdersServer) error {
	ctx, span := tracing.Tracer().Start(stream.Context(), "SubscribeSyncOrders")

	logger := ctxzap.Extract(ctx)

	operation := parseOperationToDataset(req.GetOperation())

	co := conns.SyncOrder.New(ctx, stream, req.GetOrderId(), operation.ToString())

	if os.Getenv("DEBUG") == "true" {
		logger.Info(StrNewConnSyncOrders, zap.String("orderID", req.GetOrderId()), zap.String("operation", operation.ToString()))
	}

	span.End()

	select {
	case <-stream.Context().Done():
		break
	case err := <-co.GetError():
		logger.Sugar().Infof("%s: %v", StrSubscribeSyncOrders, err)
		err = fmt.Errorf("%s: %v", StrSubscribeSyncOrders, err)
		return status.Error(codes.InvalidArgument, err.Error())
	}

	co.Stop()
	conns.SyncOrder.Clean()

	return nil
}

