```cpp
#include <iostream>
#include <string>
#include <vector>
#include <bitset>

std::vector<bool> hexStringToBoolVector(const std::string& hexStr, size_t length) {
    std::vector<bool> boolVector(length, false);
    size_t hexChars = hexStr.size();
    size_t boolIndex = 0;

    for (size_t i = 0; i < hexChars && boolIndex < length; ++i, ++boolIndex) {
        uint8_t byte = (hexStr[i] >= '0' && hexStr[i] <= '9') ? (hexStr[i] - '0') : ((hexStr[i] >= 'A' && hexStr[i] <= 'F') ? (hexStr[i] - 'A' + 10) : 0);
        for (int j = 3; j >= 0 && boolIndex < length; --j, ++boolIndex) {
            boolVector[boolIndex] = (byte >> j) & 1;
        }
    }

    return boolVector;
}

template <size_t N>
std::bitset<N> hexStringToBitset(const std::string& hexStr) {
    std::bitset<N> bitset;
    size_t hexChars = hexStr.size();
    size_t bitIndex = 0;

    for (size_t i = 0; i < hexChars && bitIndex < N; ++i, bitIndex += 4) {
        uint8_t byte = (hexStr[i] >= '0' && hexStr[i] <= '9') ? (hexStr[i] - '0') : ((hexStr[i] >= 'A' && hexStr[i] <= 'F') ? (hexStr[i] - 'A' + 10) : 0);
        for (int j = 3; j >= 0 && bitIndex < N; --j, ++bitIndex) {
            bitset[bitIndex] = (byte >> j) & 1;
        }
    }

    return bitset;
}

