```javascript
import { useState, useEffect, useRef } from 'react';

function getElementRect(element) {
  if (!element) return { top: 0, left: 0, width: 0, height: 0 };
 const { top, left, width, height } = element.getBoundingClientRect();
  return { top, left, width, height };
}

function isElementVisible(elementRect, viewportRect) {
  return (
    elementRect.top >= viewportRect.top &&
    elementRect.left >= viewportRect.left &&
    elementRect.bottom <= viewportRect.bottom &&
    elementRect.right <= viewportRect.right
  );
}

function useElementVisibility(ref) {
 const [isVisible, setIsVisible] = useState(false);
 const viewportRect = useRef({ top: 0, left: 0, width: 0, height: 0 });

  useEffect(() => {
    const handleScroll = () => {
      const elementRect = getElementRect(ref.current);
      setIsVisible(isElementVisible(elementRect, viewportRect.current));
    };

    const handleResize = () => {
      viewportRect.current = {
        top: 0,
        left: 0,
        width: window.innerWidth,
        height: window.innerHeight,
      };
      handleScroll();
    };

    window.addEventListener('scroll', handleScroll);
    window.addEventListener('resize', handleResize);

    handleScroll();

    return () => {
      window.removeEventListener('scroll', handleScroll);
      window.removeEventListener('resize', handleResize);
    };
  }, [ref]);

  return isVisible;
}

export default useElementVisibility;
```

Here's how you can use this hook in your component:

```javascript
import useElementVisibility from './useElementVisibility';

function MyComponent() {
 const ref = useRef(null);
 const isVisible = useElementVisibility(ref);

  return (
    <div ref={ref}>
      {isVisible ? 'I am visible' : 'I am not visible'}
    </div>
  );
}
```

This hook uses the `getBoundingClientRect()` method to get the position and size of the element, and checks if it's within the viewport rect. It also listens to the `scroll` and `resize` events to update the visibility state.

